import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Trash2, X, Save 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(true);
  
  const [novoCartao, setNovoCartao] = useState({
    nome: '',
    limite: '',
    dia_fechamento: '',
    dia_vencimento: '',
    cor: '#4f46e5'
  });

  useEffect(() => {
    fetchCartoes();
  }, []);

  async function fetchCartoes() {
    setLoading(true);
    const { data, error } = await supabase
      .from('cartoes')
      .select('*')
      .order('created_at', { ascending: false });

    if (!error) setCartoes(data || []);
    setLoading(false);
  }

  async function handleSave(e) {
    e.preventDefault();
    
    if (!novoCartao.nome || !novoCartao.limite) {
      alert("Por favor, preencha o nome e o limite.");
      return;
    }

    // O Supabase gera o ID automaticamente se não enviarmos um
    const { error } = await supabase
      .from('cartoes')
      .insert([
        { 
          nome: novoCartao.nome, 
          limite: parseFloat(novoCartao.limite), 
          dia_fechamento: parseInt(novoCartao.dia_fechamento) || null, 
          dia_vencimento: parseInt(novoCartao.dia_vencimento) || null, 
          cor: novoCartao.cor 
        }
      ]);

    if (error) {
      alert("Erro ao salvar cartão. Verifique se a tabela 'cartoes' existe.");
    } else {
      setShowModal(false);
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#4f46e5' });
      fetchCartoes();
    }
  }

  async function handleDelete(id) {
    if (window.confirm("Deseja realmente excluir este cartão?")) {
      const { error } = await supabase
        .from('cartoes')
        .delete()
        .eq('id', id);

      if (error) alert("Erro ao excluir.");
      else fetchCartoes();
    }
  }

  const formatMoney = (v) => 
    `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '1.8rem' }}>Meus Cartões</h1>
          <p style={{ color: 'var(--text-muted)', margin: '4px 0 0 0' }}>Gerencie seus limites e faturas.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={20} /> Adicionar Cartão
        </button>
      </div>

      {loading ? <p>Carregando...</p> : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '24px' }}>
          {cartoes.map(cartao => (
            <div key={cartao.id} className="card" style={{ 
              background: `linear-gradient(135deg, ${cartao.cor}, #1e293b)`, 
              color: 'white',
              padding: '24px',
              position: 'relative'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <span style={{ fontWeight: 700, fontSize: '1.1rem' }}>{cartao.nome}</span>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <CreditCard opacity={0.5} />
                  <Trash2 
                    size={18} 
                    style={{ cursor: 'pointer', opacity: 0.7 }} 
                    onClick={() => handleDelete(cartao.id)}
                  />
                </div>
              </div>
              <div style={{ marginBottom: '20px' }}>
                <small style={{ opacity: 0.7, fontSize: '0.7rem' }}>LIMITE TOTAL</small>
                <div style={{ fontSize: '1.5rem', fontWeight: 700 }}>{formatMoney(cartao.limite)}</div>
              </div>
              <div style={{ display: 'flex', gap: '20px', fontSize: '0.8rem' }}>
                <div>Fec. <strong>{cartao.dia_fechamento || '--'}</strong></div>
                <div>Venc. <strong>{cartao.dia_vencimento || '--'}</strong></div>
              </div>
            </div>
          ))}
        </div>
      )}

      {showModal && (
        <div className="modal-overlay">
          <div className="modal-content fade-in">
            <div className="modal-header">
              <h3>Novo Cartão</h3>
              <button className="btn-close" onClick={() => setShowModal(false)}>
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSave}>
              <div style={{ marginBottom: '16px' }}>
                <label className="label-hint">Nome do Banco / Cartão</label>
                <input 
                  className="form-control"
                  placeholder="Ex: Nubank, Inter..."
                  value={novoCartao.nome}
                  onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})}
                  required
                />
              </div>

              <div style={{ marginBottom: '16px' }}>
                <label className="label-hint">Limite de Crédito</label>
                <input 
                  className="form-control"
                  type="number"
                  placeholder="0.00"
                  value={novoCartao.limite}
                  onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})}
                  required
                />
              </div>

              <div className="form-grid">
                <div>
                  <label className="label-hint">Dia Fechamento</label>
                  <input 
                    className="form-control"
                    type="number"
                    min="1" max="31"
                    placeholder="1-31"
                    value={novoCartao.dia_fechamento}
                    onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})}
                  />
                </div>
                <div>
                  <label className="label-hint">Dia Vencimento</label>
                  <input 
                    className="form-control"
                    type="number"
                    min="1" max="31"
                    placeholder="1-31"
                    value={novoCartao.dia_vencimento}
                    onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})}
                  />
                </div>
              </div>

              <div className="color-picker-container" style={{ marginTop: '16px' }}>
                <label className="label-hint">Cor do Cartão</label>
                <input 
                  type="color"
                  className="color-input"
                  style={{ height: '40px', padding: '2px' }}
                  value={novoCartao.cor}
                  onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})}
                />
              </div>

              <button type="submit" className="btn-primary" style={{ width: '100%', marginTop: '20px' }}>
                <Save size={20} /> Salvar Cartão
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cartoes;
